const row = $input.first().json;

const now = new Date();
const pad = (n) => String(n).padStart(2, '0');

const ticket_id = `TKT-${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}-${Date.now().toString().slice(-4)}`;

const created_at = now.toISOString();

return {
  ticket_id,
  created_at,
  full_name: row['Full Name']?.trim() || '',
  email: row['Email Address']?.trim().toLowerCase() || '',
  subject: row['Subject']?.trim() || '',
  message: row['Message']?.trim() || '',
};

const ticket = $('Normalize Input').first().json;
const items = $input.all();
const customer = items.length ? items[0].json : null;

if (!customer || !customer.customer_id) {
  return [{
    json: {
      ...ticket,
      customer_found: false,
      customer_id: null,
      plan: null,
      account_status: null,
    }
  }];
}

return [{
  json: {
    ...ticket,
    customer_found: true,
    customer_id: customer.customer_id,
    plan: customer.plan,
    account_status: customer.account_status,
    preferred_language: customer.preferred_language,
    notes: customer.notes,
  }
}];

const matches = $input.first().json.matches;

const chunks = matches.map(m => m.metadata.text).join('\n\n---\n\n');

return {
  ...$('Merge Customer Data').first().json,
  rag_chunks: chunks
};

textOptions.schema:
{
  "type": "object",
  "additionalProperties": false,
  "properties": {
    "category": {
      "type": "string",
      "enum": ["billing", "technical", "account", "general"],
      "description": "High-level classification of the user request"
    },
    "priority": {
      "type": "string",
      "enum": ["low", "medium", "high"],
      "description": "Urgency of the issue based on user impact"
    },
    "confidence": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Model confidence in BOTH category and intent classification based on available context (0 = uncertain, 1 = fully certain)"
    },
    "requires_human": {
      "type": "boolean",
      "description": "True if the issue should be handled by a human due to uncertainty, missing context, or sensitivity"
    },
    "intent": {
      "type": "string",
      "description": "Short phrase (max 6–10 words) describing the user's goal"
    }
  },
  "required": [
    "category",
    "priority",
    "confidence",
    "requires_human",
    "intent"
  ]
}

